// WF_CREATE_PROJECT_FROM_ANALYSIS — Validate payload, auth check.
// Extract: analysis_group_id, niche_name, niche_description, include_channels.

const raw = $input.first().json;
const payload = raw.body || raw;

const analysisGroupId = (payload.analysis_group_id || '').trim();
const nicheName = (payload.niche_name || '').trim();
const nicheDescription = (payload.niche_description || '').trim();
const includeChannels = Array.isArray(payload.include_channels) ? payload.include_channels : [];

if (!analysisGroupId) {
  return [{ json: { success: false, error: 'analysis_group_id is required', http_status: 400 } }];
}
if (!nicheName) {
  return [{ json: { success: false, error: 'niche_name is required', http_status: 400 } }];
}

return [{ json: {
  success: true,
  analysis_group_id: analysisGroupId,
  niche_name: nicheName,
  niche_description: nicheDescription,
  include_channels: includeChannels,
  http_status: 200
} }];

// Fetch completed channel_analyses + channel_comparison_reports for this group.

const data = $input.first().json;
if (!data.success) return [{ json: data }];

const groupId = data.analysis_group_id;
const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

try {
  // Fetch completed analyses
  const analysesRes = await fetch(
    `${supabaseUrl}/rest/v1/channel_analyses?analysis_group_id=eq.${groupId}&status=eq.completed&select=*`,
    { method: 'GET', headers: sbHeaders }
  );
  if (!analysesRes.ok) {
    const errText = await analysesRes.text();
    // Also fetch niche viability report
  let viabilityReport = null;
  try {
    const vResp = await fetch(
      supabaseUrl + '/rest/v1/niche_viability_reports?analysis_group_id=eq.' + groupId + '&select=*&order=created_at.desc&limit=1',
      { headers: sbHeaders }
    );
    const vRows = await vResp.json();
    viabilityReport = Array.isArray(vRows) && vRows[0] ? vRows[0] : null;
  } catch (e) { /* ignore */ }

  return [{ json: { ...data, success: false, error: `Fetch analyses failed: HTTP ${analysesRes.status}: ${errText.slice(0, 200)}`, http_status: 500 } }];
  }
  const analyses = await analysesRes.json();

  // Fetch comparison report
  const reportRes = await fetch(
    `${supabaseUrl}/rest/v1/channel_comparison_reports?analysis_group_id=eq.${groupId}&select=*&order=created_at.desc&limit=1`,
    { method: 'GET', headers: sbHeaders }
  );
  let report = null;
  if (reportRes.ok) {
    const reports = await reportRes.json();
    report = Array.isArray(reports) && reports[0] ? reports[0] : null;
  }

  if (!Array.isArray(analyses) || analyses.length === 0) {
    // Also fetch niche viability report
  let viabilityReport = null;
  try {
    const vResp = await fetch(
      supabaseUrl + '/rest/v1/niche_viability_reports?analysis_group_id=eq.' + groupId + '&select=*&order=created_at.desc&limit=1',
      { headers: sbHeaders }
    );
    const vRows = await vResp.json();
    viabilityReport = Array.isArray(vRows) && vRows[0] ? vRows[0] : null;
  } catch (e) { /* ignore */ }

  return [{ json: { ...data, success: false, error: 'No completed analyses found for this group', http_status: 404 } }];
  }

  // Also fetch niche viability report
  let viabilityReport = null;
  try {
    const vResp = await fetch(
      supabaseUrl + '/rest/v1/niche_viability_reports?analysis_group_id=eq.' + groupId + '&select=*&order=created_at.desc&limit=1',
      { headers: sbHeaders }
    );
    const vRows = await vResp.json();
    viabilityReport = Array.isArray(vRows) && vRows[0] ? vRows[0] : null;
  } catch (e) { /* ignore */ }

  return [{ json: { ...data, analyses, comparison_report: report,
    viability_report: viabilityReport, failed: false } }];
} catch (e) {
  // Also fetch niche viability report
  let viabilityReport = null;
  try {
    const vResp = await fetch(
      supabaseUrl + '/rest/v1/niche_viability_reports?analysis_group_id=eq.' + groupId + '&select=*&order=created_at.desc&limit=1',
      { headers: sbHeaders }
    );
    const vRows = await vResp.json();
    viabilityReport = Array.isArray(vRows) && vRows[0] ? vRows[0] : null;
  } catch (e) { /* ignore */ }

  return [{ json: { ...data, success: false, error: `Exception: ${e.message}`, http_status: 500 } }];
}

const data = $input.first().json;
if (data.failed || !data.success) return [{ json: data }];

const analyses = data.analyses || [];
const report = data.comparison_report;
const viability = data.viability_report;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
  'Content-Type': 'application/json'
};

// Aggregate ALL comment insights across channels
const allContentGaps = [];
const allPainPoints = [];
const allRequestedTopics = [];
const allTopQuestions = [];
const allCompetitorMentions = [];
for (const a of analyses) {
  const ci = a.comment_insights;
  if (ci) {
    if (ci.content_gaps) allContentGaps.push(...ci.content_gaps);
    if (ci.pain_points) allPainPoints.push(...ci.pain_points);
    if (ci.requested_topics) allRequestedTopics.push(...ci.requested_topics);
    if (ci.top_questions) allTopQuestions.push(...ci.top_questions);
    if (ci.competitor_mentions) allCompetitorMentions.push(...ci.competitor_mentions);
  }
}

const channelAnalysisContext = {
  blue_ocean_gaps: report?.combined_blue_ocean_gaps || (viability?.blue_ocean_opportunities || []),
  differentiation_strategy: report?.differentiation_strategy || (viability?.differentiation_strategy || ''),
  content_pillars: report?.recommended_content_pillars || (viability?.recommended_content_pillars || []),
  topic_landscape: report?.combined_topic_landscape || {},
  saturation_map: report?.combined_saturation_map || (viability?.saturated_topics || []),
  overall_verdict: report?.overall_verdict || (viability?.viability_verdict || null),
  overall_verdict_score: report?.overall_verdict_score || (viability?.viability_score || null),
  channel_count: analyses.length,
  monetization_score: viability?.monetization_score || null,
  audience_demand_score: viability?.audience_demand_score || null,
  competition_gap_score: viability?.competition_gap_score || null,
  entry_difficulty_score: viability?.entry_difficulty_score || null,
  estimated_rpm: { low: viability?.estimated_rpm_low, mid: viability?.estimated_rpm_mid, high: viability?.estimated_rpm_high },
  sponsorship_potential: viability?.sponsorship_potential || null,
  moat_indicators: viability?.moat_indicators || null,
  posting_frequency_benchmark: viability?.posting_frequency_benchmark || null,
  audience_size_estimate: viability?.audience_size_estimate || null,
  engagement_benchmarks: viability?.engagement_benchmarks || null,
  comment_content_gaps: [...new Set(allContentGaps)],
  comment_pain_points: [...new Set(allPainPoints)],
  comment_requested_topics: [...new Set(allRequestedTopics)],
  comment_top_questions: [...new Set(allTopQuestions)],
  comment_competitor_mentions: [...new Set(allCompetitorMentions)],
};

const scriptReferenceData = {
  per_channel: analyses.map(a => ({
    channel_name: a.channel_name || 'Unknown',
    scripting_depth: a.scripting_depth || {},
    content_style: a.content_style || null,
    target_audience: a.target_audience_description || null,
    strengths: a.strengths || [],
    weaknesses: a.weaknesses || [],
    posting_schedule: a.posting_schedule || null,
  })),
  targets: viability?.script_depth_targets || null,
};

const nicheDesc = data.niche_description || report?.recommended_niche_description || '';

const projectRow = {
  name: data.niche_name,
  niche: data.niche_name,
  niche_description: nicheDesc.slice(0, 10000),
  channel_analysis_context: channelAnalysisContext,
  script_reference_data: scriptReferenceData,
  analysis_group_id: data.analysis_group_id,
  niche_viability_score: viability?.viability_score || null,
  niche_viability_verdict: viability?.viability_verdict || null,
  topics_to_avoid: viability?.topics_to_avoid || [],
  recommended_topics: viability?.recommended_topics || [],
  recommended_angle: viability?.recommended_angle || null,
  revenue_projections: viability?.revenue_projections || null,
  script_depth_targets: viability?.script_depth_targets || null,
  title_dna_patterns: viability?.title_dna_patterns || null,
  thumbnail_dna_patterns: viability?.thumbnail_dna_patterns || null,
  status: 'created'
};

try {
  const res = await fetch(supabaseUrl + '/rest/v1/projects', {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify(projectRow)
  });
  if (!res.ok) {
    const errText = await res.text();
    return [{ json: { ...data, success: false, error: 'HTTP ' + res.status + ': ' + errText.slice(0, 200) } }];
  }
  const inserted = await res.json();
  const project = Array.isArray(inserted) && inserted[0] ? inserted[0] : null;
  if (!project || !project.id) {
    return [{ json: { ...data, success: false, error: 'Empty insert' } }];
  }
  return [{ json: { ...data, project_id: project.id, failed: false } }];
} catch (e) {
  return [{ json: { ...data, success: false, error: e.message } }];
}

// For each selected analysis (filtered by include_channels): INSERT into competitor_channels.
// Uses ON CONFLICT (project_id, channel_id) DO NOTHING for idempotency.

const data = $input.first().json;
if (data.failed || !data.project_id) return [{ json: data }];

const projectId = data.project_id;
const analyses = data.analyses || [];
const includeChannels = data.include_channels || [];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Filter analyses by include_channels if specified, otherwise include all
const selected = includeChannels.length > 0
  ? analyses.filter(a => includeChannels.includes(a.id))
  : analyses;

let seededCount = 0;
let errors = [];

for (const a of selected) {
  const row = {
    project_id: projectId,
    channel_id: a.youtube_channel_id || null,
    channel_name: a.channel_name || 'Unknown',
    channel_url: a.channel_url || null,
    channel_handle: a.custom_url || null,
    added_from: 'channel_analyzer',
    subscriber_count: a.subscriber_count || 0,
    total_video_count: a.video_count || 0,
    total_view_count: a.total_view_count || 0,
    is_active: true
  };

  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/competitor_channels`, {
      method: 'POST',
      headers: {
        ...sbHeaders,
        'Prefer': 'return=minimal,resolution=ignore-duplicates'
      },
      body: JSON.stringify(row)
    });
    if (res.ok || res.status === 409) {
      seededCount++;
    } else {
      const errText = await res.text();
      errors.push(`${a.channel_name}: HTTP ${res.status}: ${errText.slice(0, 100)}`);
    }
  } catch (e) {
    errors.push(`${a.channel_name}: ${e.message}`);
  }
}

return [{ json: { ...data, seeded_competitors: seededCount, seed_errors: errors, failed: false } }];

// For each analysis with thumbnail_patterns: INSERT into style_profiles.

const data = $input.first().json;
if (data.failed || !data.project_id) return [{ json: data }];

const projectId = data.project_id;
const analyses = data.analyses || [];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

let seededCount = 0;
let errors = [];

for (const a of analyses) {
  // Only seed if analysis has thumbnail_patterns or title_patterns
  if (!a.thumbnail_patterns && !a.title_patterns) continue;

  const row = {
    project_id: projectId,
    channel_id: a.youtube_channel_id || null,
    channel_name: a.channel_name || 'Unknown',
    title_formulas: a.title_patterns || {},
    thumbnail_dna: a.thumbnail_patterns || {},
    content_pillars: a.primary_topics || [],
    analyzed_at: a.analyzed_at || new Date().toISOString()
  };

  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/style_profiles`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify(row)
    });
    if (res.ok) {
      seededCount++;
    } else {
      const errText = await res.text();
      errors.push(`${a.channel_name}: HTTP ${res.status}: ${errText.slice(0, 100)}`);
    }
  } catch (e) {
    errors.push(`${a.channel_name}: ${e.message}`);
  }
}

return [{ json: { ...data, seeded_styles: seededCount, style_errors: errors, failed: false } }];

// PATCH channel_analyses and channel_comparison_reports to link them to the new project.

const data = $input.first().json;
if (data.failed || !data.project_id) return [{ json: data }];

const projectId = data.project_id;
const groupId = data.analysis_group_id;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

let linkedAnalyses = false;
let linkedReport = false;
let errors = [];

// Link channel_analyses to project
try {
  const res = await fetch(
    `${supabaseUrl}/rest/v1/channel_analyses?analysis_group_id=eq.${groupId}`,
    {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ project_id: projectId })
    }
  );
  linkedAnalyses = res.ok;
  if (!res.ok) {
    const errText = await res.text();
    errors.push(`Link analyses: HTTP ${res.status}: ${errText.slice(0, 100)}`);
  }
} catch (e) {
  errors.push(`Link analyses: ${e.message}`);
}

// Link channel_comparison_reports to project
try {
  const res = await fetch(
    `${supabaseUrl}/rest/v1/channel_comparison_reports?analysis_group_id=eq.${groupId}`,
    {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ project_id: projectId })
    }
  );
  linkedReport = res.ok;
  if (!res.ok) {
    const errText = await res.text();
    errors.push(`Link report: HTTP ${res.status}: ${errText.slice(0, 100)}`);
  }
} catch (e) {
  errors.push(`Link report: ${e.message}`);
}

return [{ json: { ...data, linked_analyses: linkedAnalyses, linked_report: linkedReport, link_errors: errors, failed: false } }];

const data = $input.first().json;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
  'Content-Type': 'application/json'
};

try {
  await fetch(supabaseUrl + '/rest/v1/production_logs', {
    method: 'POST',
    headers: Object.assign({}, sbHeaders, { 'Prefer': 'return=minimal' }),
    body: JSON.stringify({
      project_id: data.project_id || null,
      topic_id: null,
      stage: 'create_project_from_analysis',
      scene_number: null,
      action: 'completed',
      status: 'success',
      duration_ms: 0,
      cost_usd: 0,
      retry_count: 0
    })
  });
} catch (_) {}

if (data.project_id) {
  try {
    await fetch(supabaseUrl + '/rest/v1/projects?id=eq.' + data.project_id, {
      method: 'PATCH',
      headers: Object.assign({}, sbHeaders, { 'Prefer': 'return=minimal' }),
      body: JSON.stringify({ status: 'ready_for_topics', updated_at: new Date().toISOString() })
    });
  } catch (_) {}
}

return [{ json: {
  success: true,
  project_id: data.project_id,
  analysis_group_id: data.analysis_group_id,
  seeded_competitors: data.seeded_competitors || 0,
  seeded_styles: data.seeded_styles || 0,
  linked_analyses: data.linked_analyses || false,
  linked_report: data.linked_report || false
} }];
